response:
Here is a simple implementation of a stack data structure using an array of maximum 100 elements in C++:

```cpp
#include <iostream>
using namespace std;

class Stack {
private:
    int arr[100];  // Array to store stack elements
    int topIndex;  // Index of the top element

public:
    Stack() {
        topIndex = -1;  // Initialize stack as empty
    }

    // Check if the stack is empty
    bool empty() {
        return topIndex == -1;
    }

    // Check if the stack is full
    bool full() {
        return topIndex == 99;
    }

    // Add an element to the top of the stack
    void push(int x) {
        if (full()) {
            cout << "Stack overflow! Cannot push " << x << endl;
            return;
        }
        arr[++topIndex] = x;
    }

    // Remove the top element from the stack
    void pop() {
        if (empty()) {
            cout << "Stack underflow! Cannot pop." << endl;
            return;
        }
        topIndex--;
    }

    // Get the top element of the stack
    int top() {
        if (empty()) {
            cout << "Stack is empty!" << endl;
            return -1;  // Return an invalid value or throw an exception
        }
        return arr[topIndex];
    }
};

int main() {
    Stack s;

    s.push(10);
    s.push(20);
    s.push(30);

    cout << "Top element: " << s.top() << endl;  // Should print 30

    s.pop();
    cout << "Top element after pop: " << s.top() << endl;  // Should print 20

    return 0;
}
```

### Explanation:
- The stack is implemented using an integer array `arr` of size 100.
- `topIndex` keeps track of the current top element's index.
- `empty()` returns true if the stack is empty.
- `full()` returns true if the stack is full.
- `push(int x)` adds an element to the top if the stack is not full.
- `pop()` removes the top element if the stack is not empty.
- `top()` returns the top element if the stack is not empty.
